const mapApiQuestion = (q) => {
  if (!q) return null;
  const DIFFICULTY_MAP = { easy: 'Oson', medium: "O'rta", hard: 'Qiyin' };
  const ENG_DIFFICULTY_MAP = {
    easy: 'Beginner',
    medium: 'Intermediate',
    hard: 'Advanced',
    beginner: 'Beginner',
    elementary: 'Elementary',
    'pre-int': 'Pre-Intermediate',
    int: 'Intermediate',
    'upper-int': 'Upper-Intermediate',
    advanced: 'Advanced',
  };
  const mappedDifficulty = q.subject === 'Ingliz tili'
    ? (ENG_DIFFICULTY_MAP[q.difficulty] || q.difficulty)
    : (DIFFICULTY_MAP[q.difficulty] || q.difficulty);
  return {
    id: String(q.id),
    backendId: q.id,
    centerId: q.center != null ? String(q.center) : null,
    subject: q.subject,
    text: q.text,
    options: Array.isArray(q.options) ? q.options : [],
    correctAnswer: q.correct_answer ?? 0,
    score: q.score ?? 3,
    difficulty: mappedDifficulty,
    source: q.source || 'manual',
    // IT (kod) savol maydonlari. Oddiy MCQ savollarda questionType='mcq'.
    questionType: q.question_type || q.questionType || 'mcq',
    programmingLanguage: q.programming_language || q.programmingLanguage || '',
    codeTemplate: q.code_template || q.codeTemplate || '',
    expectedOutput: q.expected_output || q.expectedOutput || '',
    // Judge0 test case'lar (staff savol formasida tahrirlanadi). Student
    // javobida backend bu maydonni umuman qaytarmaydi (serializer himoyasi).
    testCases: Array.isArray(q.test_cases) ? q.test_cases : (Array.isArray(q.testCases) ? q.testCases : []),
    _api: true,
  };
};

// Best-effort parse of an olympiad's scheduled start instant. Returns null
// when the olympiad has no scheduled start (e.g. legacy mock entries without
// a startDate).
const olympiadStartMoment = (olympiad) => {
  if (!olympiad) return null;
  if (olympiad.start_datetime) {
    const d = new Date(olympiad.start_datetime);
    return isNaN(d.getTime()) ? null : d;
  }
  if (olympiad.startDate) {
    const time = olympiad.startTime || '00:00';
    const d = new Date(`${olympiad.startDate}T${time.length === 5 ? `${time}:00` : time}`);
    return isNaN(d.getTime()) ? null : d;
  }
  return null;
};

