{
// pages/Analytics.jsx — Chuqur analitika sahifasi

const AnalyticsPage = ({ user, onNavigate }) => {
  const [tab, setTab] = React.useState('student');
  const isApi = !!user?._api;
  const token = isApi ? OlympyApi.getToken() : null;

  // Foydalanuvchi rollarini aniqlash — "Savollar" tab faqat
  // teacher/manager/owner uchun.
  const userRoles = user?.roles || {};
  const isStaff = ['teacher', 'manager', 'owner'].some(r => userRoles[r]?.status === 'approved');
  // Markaz id — savollar tahlili uchun. Avvalo manager, keyin teacher/owner.
  const centerId = (() => {
    for (const role of ['manager', 'owner', 'teacher']) {
      const cid = userRoles[role]?.centerId;
      if (userRoles[role]?.status === 'approved' && cid) return cid;
    }
    return null;
  })();

  // ─── O'quvchi tab data ───────────────────────────────────────────
  const monthlyRes = useApiData(
    () => isApi ? OlympyApi.getMyMonthlyStats(6, token) : Promise.resolve(null),
    [isApi],
  );
  const statsRes = useApiData(
    () => isApi ? OlympyApi.getMyStats(token) : Promise.resolve(null),
    [isApi],
  );
  const monthlyChart = React.useMemo(() => {
    const rows = monthlyRes.data?.months;
    if (!Array.isArray(rows)) return [];
    return rows.map(r => ({ label: r.label || `${r.month}-oy`, value: Math.round(r.average_score || 0) }));
  }, [monthlyRes.data]);
  const subjectRows = Array.isArray(statsRes.data?.subjects) ? statsRes.data.subjects : [];

  // ─── Savollar tab data ───────────────────────────────────────────
  const difficultyRes = useApiData(
    () => (isApi && isStaff && centerId)
      ? OlympyApi.getQuestionDifficultyStats(centerId, token)
      : Promise.resolve(null),
    [isApi, isStaff, centerId],
  );

  // ─── Markaz reytingi tab data ────────────────────────────────────
  const [regionFilter, setRegionFilter] = React.useState('');
  const ratingsRes = useApiData(
    () => isApi
      ? OlympyApi.getCenterRatings(regionFilter ? { region: regionFilter, limit: 50 } : { limit: 50 }, token)
      : Promise.resolve([]),
    [isApi, regionFilter],
  );

  // Region select uchun ro'yxat — markazlardan derive qilamiz.
  const allRegions = React.useMemo(() => {
    const set = new Set();
    (ratingsRes.data || []).forEach(r => { if (r.region) set.add(r.region); });
    return Array.from(set).sort();
  }, [ratingsRes.data]);

  const tabBtn = (key, label) => (
    <button
      key={key}
      onClick={() => setTab(key)}
      className={`px-4 py-2 rounded-xl text-sm font-semibold transition-colors ${tab === key ? 'btn-primary' : 'btn-ghost'}`}
    >{label}</button>
  );

  return (
    <div className="min-h-screen" style={{ background: '#050508' }}>
      <div className="glass border-b border-white/5 px-4 md:px-6 py-3 flex items-center gap-3">
        <button type="button" className="cursor-pointer border-0 bg-transparent p-0" onClick={() => onNavigate(roleHomePage(user))} aria-label="Dashboardga qaytish">
          <BrandLogo size="sm" />
        </button>
        <h1 className="text-white font-bold text-base md:text-lg">Analitika</h1>
        <button onClick={() => onNavigate(roleHomePage(user))} className="ml-auto btn-ghost text-xs px-4 py-2 rounded-xl flex items-center gap-1.5">
          <Icon name="arrowLeft" size={13} /> Orqaga
        </button>
      </div>

      <div className="max-w-6xl mx-auto p-3 md:p-6 space-y-4 md:space-y-6 mobile-content-pad">
        {/* Tabs */}
        <div className="flex items-center gap-2 flex-wrap glass rounded-2xl p-2">
          {tabBtn('student', "O'quvchi")}
          {isStaff && tabBtn('questions', 'Savollar')}
          {tabBtn('centers', 'Markaz reytingi')}
        </div>

        {/* O'quvchi tab */}
        {tab === 'student' && (
          <div className="space-y-4 md:space-y-6">
            <div className="glass rounded-2xl p-4 md:p-6">
              <h3 className="font-bold text-white text-sm md:text-base mb-3">Oylik o'rtacha ball (6 oy)</h3>
              {!isApi && <div className="text-xs text-white/40">Bu ma'lumot faqat backend rejimida ko'rinadi.</div>}
              {isApi && monthlyRes.loading && <div className="text-xs text-white/40">Yuklanmoqda...</div>}
              {isApi && !monthlyRes.loading && monthlyChart.length === 0 && (
                <div className="text-xs text-white/40">Hozircha natijalar yo'q.</div>
              )}
              {monthlyChart.length > 0 && (
                <div className="mt-2">
                  <BarChart data={monthlyChart} />
                </div>
              )}
            </div>

            <div className="glass rounded-2xl p-4 md:p-6">
              <h3 className="font-bold text-white text-sm md:text-base mb-3">Fanlar bo'yicha natijalar</h3>
              {isApi && statsRes.loading && <div className="text-xs text-white/40">Yuklanmoqda...</div>}
              {isApi && !statsRes.loading && subjectRows.length === 0 && (
                <div className="text-xs text-white/40">Hali fan kesimida natijalar yo'q.</div>
              )}
              {subjectRows.length > 0 && (
                <div className="space-y-3">
                  {subjectRows.map((r, i) => {
                    const avg = Math.round(r.average_score || 0);
                    return (
                      <div key={`${r.subject}-${i}`}>
                        <div className="flex justify-between text-xs mb-1 gap-2">
                          <span className="text-white/60 truncate min-w-0">
                            <span className="truncate">{r.subject || '—'}</span>
                            <span className="text-white/30 whitespace-nowrap"> · {r.attempts || 0} ta</span>
                          </span>
                          <span className={`font-medium flex-shrink-0 ${avg >= 70 ? 'text-emerald-400' : avg >= 50 ? 'text-amber-400' : 'text-rose-400'}`}>{avg}%</span>
                        </div>
                        <div className="progress-bar h-2">
                          <div className="progress-fill" style={{ width: `${avg}%`, background: avg >= 70 ? '#22c55e' : avg >= 50 ? '#f59e0b' : '#ef4444' }} />
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>

            {statsRes.data && (
              <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                <StatCard label="Jami urinishlar" value={statsRes.data.total_attempts || 0} icon={<Icon name="bolt" size={20} />} color="from-cyan-500 to-blue-600" />
                <StatCard label="O'rtacha ball" value={Math.round(statsRes.data.average_score || 0)} icon={<Icon name="chart" size={20} />} color="from-indigo-500 to-purple-600" />
                <StatCard label="Eng yaxshi o'rin" value={statsRes.data.best_rank ? `#${statsRes.data.best_rank}` : '—'} icon={<Icon name="trophy" size={20} />} color="from-amber-500 to-orange-500" />
              </div>
            )}
          </div>
        )}

        {/* Savollar tab */}
        {tab === 'questions' && isStaff && (
          <div className="space-y-4 md:space-y-6">
            <div className="glass rounded-2xl p-4 md:p-6">
              <h3 className="font-bold text-white text-sm md:text-base mb-3">Qiyinlik bo'yicha taqsimot</h3>
              {!centerId && <div className="text-xs text-white/40">Markaz topilmadi.</div>}
              {isApi && difficultyRes.loading && <div className="text-xs text-white/40">Yuklanmoqda...</div>}
              {isApi && !difficultyRes.loading && centerId && difficultyRes.data && (
                <>
                  <div className="mb-4 text-sm text-white/60">
                    Jami savollar: <span className="text-white font-bold">{difficultyRes.data.total_questions}</span>
                  </div>
                  <div className="space-y-3">
                    {(difficultyRes.data.by_difficulty || []).map((d, i) => {
                      const pct = difficultyRes.data.total_questions
                        ? Math.round((d.count / difficultyRes.data.total_questions) * 100)
                        : 0;
                      const rate = Math.round(d.avg_correct_rate || 0);
                      return (
                        <div key={i} className="rounded-2xl bg-white/5 border border-white/10 p-3 md:p-4">
                          <div className="flex items-center justify-between gap-2 mb-2 flex-wrap">
                            <div className="flex items-center gap-2">
                              <span className="text-white font-semibold">{d.label}</span>
                              <span className="chip bg-white/5 text-white/60 border border-white/10 text-[10px]">{d.count} ta</span>
                            </div>
                            <span className={`text-xs font-bold ${rate >= 70 ? 'text-emerald-400' : rate >= 50 ? 'text-amber-400' : 'text-rose-400'}`}>
                              To'g'rilik: {rate}%
                            </span>
                          </div>
                          <div className="progress-bar h-2 mb-2">
                            <div className="progress-fill" style={{ width: `${pct}%`, background: '#6366f1' }} />
                          </div>
                          <div className="flex items-center justify-between text-[10px] text-white/40">
                            <span>{pct}% bankdan</span>
                            <span>{rate}% to'g'ri javob</span>
                          </div>
                        </div>
                      );
                    })}
                    {(difficultyRes.data.by_difficulty || []).length === 0 && (
                      <div className="text-xs text-white/40">Savollar topilmadi.</div>
                    )}
                  </div>
                </>
              )}
              {difficultyRes.error && (
                <div className="text-xs text-rose-300">Yuklab bo'lmadi: {String(difficultyRes.error?.message || '')}</div>
              )}
            </div>
          </div>
        )}

        {/* Markaz reytingi tab */}
        {tab === 'centers' && (
          <div className="space-y-4 md:space-y-6">
            <div className="glass rounded-2xl p-4 md:p-6">
              <div className="flex items-center justify-between gap-3 mb-4 flex-wrap">
                <h3 className="font-bold text-white text-sm md:text-base">Markazlar reytingi</h3>
                <div className="flex items-center gap-2 flex-wrap">
                  <select
                    value={regionFilter}
                    onChange={e => setRegionFilter(e.target.value)}
                    className="glass border border-white/10 rounded-xl px-3 py-2 text-xs text-white bg-transparent"
                  >
                    <option value="" className="bg-[#12141a]">Barcha viloyatlar</option>
                    {allRegions.map(r => <option key={r} value={r} className="bg-[#12141a]">{r}</option>)}
                  </select>
                </div>
              </div>
              {isApi && ratingsRes.loading && <div className="text-xs text-white/40">Yuklanmoqda...</div>}
              {isApi && !ratingsRes.loading && (ratingsRes.data || []).length === 0 && (
                <div className="text-xs text-white/40">Reyting bo'sh.</div>
              )}
              {(ratingsRes.data || []).length > 0 && (
                <div className="overflow-x-auto">
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="text-left text-white/40 text-xs">
                        <th className="py-2 pr-3">#</th>
                        <th className="py-2 pr-3">Markaz</th>
                        <th className="py-2 pr-3 hidden md:table-cell">Shahar</th>
                        <th className="py-2 pr-3">O'rt. ball</th>
                        <th className="py-2 pr-3 hidden md:table-cell">Urinishlar</th>
                        <th className="py-2">Reyting</th>
                      </tr>
                    </thead>
                    <tbody>
                      {(ratingsRes.data || []).map(r => (
                        <tr key={r.center_id} className="border-t border-white/5">
                          <td className="py-2 pr-3 text-white/60 font-bold">{r.rank}</td>
                          <td className="py-2 pr-3 text-white font-medium">{r.center_name}</td>
                          <td className="py-2 pr-3 text-white/60 hidden md:table-cell">{r.city || r.region || '—'}</td>
                          <td className="py-2 pr-3 text-emerald-300 font-bold">{r.average_score}</td>
                          <td className="py-2 pr-3 text-white/60 hidden md:table-cell">{r.total_attempts}</td>
                          <td className="py-2 text-amber-300 font-semibold">
                            <span className="inline-flex items-center gap-1">
                              <Icon name="star" size={12} />
                              {r.rating?.toFixed ? r.rating.toFixed(1) : r.rating}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

Object.assign(window, { AnalyticsPage });


Object.assign(moduleScope, { AnalyticsPage });
}
var AnalyticsPage = moduleScope.AnalyticsPage;

// pages/ParentDashboard.jsx
{
// pages/ParentDashboard.jsx — Ota-ona / Kuzatuvchi paneli

const ParentDashboard = ({ user, onNavigate, onLogout }) => {
  const [page, setPage] = React.useState('home');
  const [mobileMenu, setMobileMenu] = React.useState(false);
  const [phoneInput, setPhoneInput] = React.useState('+998');
  const [linkError, setLinkError] = React.useState('');
  const [linkSuccess, setLinkSuccess] = React.useState('');
  const [selectedChild, setSelectedChild] = React.useState(null);
  const [downloadingReportId, setDownloadingReportId] = React.useState(null);

  const isApi = !!user?._api;
  const token = isApi ? OlympyApi.getToken() : null;

  const childrenRes = useApiData(
    () => isApi ? OlympyApi.getChildren(token) : Promise.resolve([]),
    [isApi],
  );
  const children = childrenRes.data || [];

  const [predictionsMap, setPredictionsMap] = React.useState({});
  const [predictionsLoading, setPredictionsLoading] = React.useState(false);
  const [digestTogglingId, setDigestTogglingId] = React.useState(null);
  const [sendingDigestId, setSendingDigestId] = React.useState(null);

  const fetchPredictions = React.useCallback(async (studentId) => {
    if (!studentId || predictionsMap[studentId]) return;
    setPredictionsLoading(true);
    try {
      const resp = await OlympyApi.getChildPredictions(studentId, token);
      if (resp) {
        setPredictionsMap(prev => ({ ...prev, [studentId]: resp }));
      }
    } catch {}
    setPredictionsLoading(false);
  }, [token, predictionsMap]);

  React.useEffect(() => {
    if (selectedChild) {
      fetchPredictions(selectedChild.student_id);
    }
  }, [selectedChild, fetchPredictions]);

  const handleToggleDigest = async (studentId, currentVal) => {
    setDigestTogglingId(studentId);
    try {
      const nextVal = !currentVal;
      await OlympyApi.toggleWeeklyDigest(studentId, nextVal, token);
      childrenRes.reload();
      if (selectedChild && selectedChild.student_id === studentId) {
        setSelectedChild(prev => ({ ...prev, weekly_digest_enabled: nextVal }));
      }
    } catch (err) {
      alert("Haftalik hisobot rejimini o'zgartirib bo'lmadi");
    } finally {
      setDigestTogglingId(null);
    }
  };

  const handleSendTestDigest = async (studentId) => {
    setSendingDigestId(studentId);
    try {
      const resp = await OlympyApi.sendTestWeeklyDigest(studentId, token);
      alert(resp?.detail || "Haftalik hisobot Telegram orqali jo'natildi!");
    } catch (err) {
      alert(err.message || "Telegramga xabar yuborib bo'lmadi. Telegram profil bog'langanligini tekshiring.");
    } finally {
      setSendingDigestId(null);
    }
  };

  const handleLink = async () => {
    setLinkError('');
    setLinkSuccess('');
    const phone = (phoneInput || '').trim();
    if (!phone || phone.length < 10) {
      setLinkError("Telefon raqamni to'liq kiriting");
      return;
    }
    try {
      await OlympyApi.linkChild(phone, token);
      setLinkSuccess("Farzand qo'shildi!");
      setPhoneInput('+998');
      childrenRes.reload();
      setTimeout(() => setLinkSuccess(''), 3000);
    } catch (err) {
      setLinkError(OlympyApi.toUserMessage?.(err) || "Qo'shib bo'lmadi");
    }
  };

  const handleUnlink = async (studentId) => {
    if (!confirm("Farzandni olib tashlashni tasdiqlaysizmi?")) return;
    try {
      await OlympyApi.unlinkChild(studentId, token);
      childrenRes.reload();
    } catch (err) {
      alert(OlympyApi.toUserMessage?.(err) || "O'chirib bo'lmadi");
    }
  };

  const handleDownloadReport = async (studentId, studentName) => {
    setDownloadingReportId(studentId);
    try {
      const blob = await OlympyApi.downloadChildReport(studentId, token);
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      const cleanedName = (studentName || 'o_quvchi').replace(/\s+/g, '_');
      a.download = `hisobot-${cleanedName}.pdf`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      alert(OlympyApi.toUserMessage?.(err) || "Hisobotni yuklab bo'lmadi");
    } finally {
      setDownloadingReportId(null);
    }
  };

  const navItems = [
    { key: 'home', icon: 'home', label: 'Uy' },
    { key: 'children', icon: 'users', label: 'Farzandlarim' },
    { key: 'profile', icon: 'user', label: 'Profil' },
  ];

  const renderHome = () => (
    <div className="p-3 md:p-6 space-y-4 md:space-y-6 mobile-content-pad">
      <div>
        <h2 className="text-xl md:text-2xl font-black text-white">Salom, {user.name?.split(' ')[0] || 'Ota-ona'}! 👋</h2>
        <p className="text-white/40 text-xs md:text-sm mt-1">Farzandingizning o'qish jarayonini kuzating</p>
      </div>

      {childrenRes.loading && (
        <div className="text-white/40 text-sm">Yuklanmoqda...</div>
      )}
      {!childrenRes.loading && children.length === 0 && (
        <EmptyState
          icon="users"
          title="Farzand qo'shilmagan"
          desc="Farzandingiz telefon raqami orqali uni ro'yxatga oling"
          action={
            <button onClick={() => setPage('children')} className="btn-primary px-5 py-2.5 rounded-xl text-sm font-semibold">
              Farzand qo'shish
            </button>
          }
        />
      )}

      {children.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {children.map(child => {
            const latest = (child.attempts || [])[0];
            const avg = (child.attempts || []).length
              ? Math.round((child.attempts.reduce((s, a) => s + (a.score || 0), 0) / child.attempts.length))
              : 0;
            return (
              <div key={child.student_id} className="glass rounded-2xl p-4 md:p-5 card-hover">
                <div className="flex items-start gap-3 mb-3">
                  <Avatar name={child.full_name} src={child.avatar_url} size={48} />
                  <div className="flex-1 min-w-0">
                    <div className="font-semibold text-white flex items-center gap-1.5 truncate">
                      {child.full_name}
                      {!!child.streak_count && (
                        <span className="inline-flex items-center gap-0.5 text-[10px] font-black text-orange-400 bg-orange-500/10 border border-orange-500/25 px-1.5 py-0.5 rounded-lg animate-pulse" title="Ketma-ket faol kunlari">
                          🔥 {child.streak_count} kun
                        </span>
                      )}
                    </div>
                    <div className="text-xs text-white/40 truncate">{child.phone}</div>
                  </div>
                </div>
                <div className="grid grid-cols-3 gap-2 text-center mb-3">
                  <div className="glass rounded-xl py-2">
                    <div className="text-xs text-white/40">Tadbirlar</div>
                    <div className="text-lg font-bold text-white">{(child.attempts || []).length}</div>
                  </div>
                  <div className="glass rounded-xl py-2">
                    <div className="text-xs text-white/40">O'rt. ball</div>
                    <div className={`text-lg font-bold ${avg >= 70 ? 'text-emerald-400' : avg >= 50 ? 'text-amber-400' : 'text-white/50'}`}>{avg || '—'}</div>
                  </div>
                  <div className="glass rounded-xl py-2">
                    <div className="text-xs text-white/40">Eng yaxshi</div>
                    <div className="text-lg font-bold text-amber-300">
                      {(child.attempts || []).reduce((m, a) => a.score > m ? a.score : m, 0) || '—'}
                    </div>
                  </div>
                </div>
                {latest && (
                  <div className="rounded-xl bg-white/5 p-3 mb-3 border border-white/10">
                    <div className="text-[10px] text-white/40 uppercase mb-1">So'nggi natija</div>
                    <div className="text-sm font-medium text-white truncate">{latest.olympiad_title}</div>
                    <div className="flex items-center justify-between mt-1 text-xs">
                      <span className="text-white/60">{latest.subject}</span>
                      <span className={`font-bold ${latest.score >= 70 ? 'text-emerald-400' : latest.score >= 50 ? 'text-amber-400' : 'text-rose-400'}`}>
                        {latest.score} ball
                      </span>
                    </div>
                  </div>
                )}
                <div className="flex gap-2">
                  <button
                    onClick={() => handleDownloadReport(child.student_id, child.full_name)}
                    disabled={downloadingReportId === child.student_id}
                    className="flex-1 btn-primary py-2.5 rounded-xl text-xs font-semibold flex items-center justify-center gap-1.5 min-h-[40px] disabled:opacity-50"
                  >
                    {downloadingReportId === child.student_id ? (
                      <>
                        <span className="w-3.5 h-3.5 rounded-full border border-white/20 border-t-white animate-spin" />
                        Yuklanmoqda...
                      </>
                    ) : (
                      <>
                        <Icon name="download" size={13} />
                        Hisobot
                      </>
                    )}
                  </button>
                  <button
                    onClick={() => setSelectedChild(child)}
                    className="flex-1 btn-ghost py-2.5 rounded-xl text-xs font-semibold"
                  >Batafsil</button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );

  const renderChildren = () => (
    <div className="p-3 md:p-6 space-y-4 md:space-y-6 mobile-content-pad">
      <div className="glass rounded-2xl p-4 md:p-6">
        <h3 className="font-bold text-white text-sm md:text-base mb-3">Yangi farzand qo'shish</h3>
        <p className="text-xs text-white/40 mb-4">Farzandingiz allaqachon Olympy'da ro'yxatdan o'tgan bo'lishi kerak. Uning telefon raqamini kiriting.</p>
        <div className="flex gap-2 flex-wrap">
          <input
            type="tel"
            value={phoneInput}
            onChange={e => setPhoneInput(formatUzPhoneInput ? formatUzPhoneInput(e.target.value) : e.target.value)}
            placeholder="+998 90 123 45 67"
            className="glass border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white bg-transparent flex-1 min-w-[200px]"
          />
          <button onClick={handleLink} className="btn-primary px-5 py-2.5 rounded-xl text-sm font-semibold">
            Qo'shish
          </button>
        </div>
        {linkError && <div className="text-xs text-rose-400 mt-2">{linkError}</div>}
        {linkSuccess && <div className="text-xs text-emerald-400 mt-2">{linkSuccess}</div>}
      </div>

      <div className="glass rounded-2xl p-4 md:p-6">
        <h3 className="font-bold text-white text-sm md:text-base mb-3">Mening farzandlarim</h3>
        {childrenRes.loading && <div className="text-xs text-white/40">Yuklanmoqda...</div>}
        {!childrenRes.loading && children.length === 0 && (
          <div className="text-xs text-white/40">Hozircha farzand qo'shilmagan.</div>
        )}
        {children.length > 0 && (
          <div className="space-y-3">
            {children.map(child => (
              <div key={child.student_id} className="flex items-center gap-3 p-3 rounded-xl glass">
                <Avatar name={child.full_name} src={child.avatar_url} size={40} />
                <div className="flex-1 min-w-0">
                  <div className="font-medium text-white truncate">{child.full_name}</div>
                  <div className="text-xs text-white/40 truncate">{child.phone}</div>
                </div>
                <button
                  onClick={() => handleUnlink(child.student_id)}
                  className="text-xs text-rose-300 hover:text-rose-200 px-3 py-1.5 rounded-lg border border-rose-500/20 hover:border-rose-500/40"
                >Olib tashlash</button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );

  const renderProfile = () => (
    <div className="p-3 md:p-6 mobile-content-pad">
      <div className="glass rounded-2xl p-5">
        <div className="flex items-center gap-4 mb-4">
          <Avatar name={user.name} src={user.avatarUrl} size={56} />
          <div className="flex-1 min-w-0">
            <div className="text-white font-bold truncate">{user.name}</div>
            <div className="text-xs text-white/40 truncate">{user.phone}</div>
            <div className="text-xs text-indigo-300 mt-1">Ota-ona / Kuzatuvchi</div>
          </div>
        </div>
        <div className="space-y-2">
          <button onClick={() => onNavigate('profile')} className="w-full btn-ghost text-sm py-2.5 rounded-xl">Asosiy profilni ochish</button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar
        items={navItems}
        activePage={page}
        setPage={setPage}
        user={{ ...user, role: 'Ota-ona' }}
        onLogout={onLogout}
        logoClick={() => onNavigate('landing')}
        mobileOpen={mobileMenu}
        onMobileClose={() => setMobileMenu(false)}
      />
      <div className="flex-1 flex flex-col overflow-hidden">
        <Topbar
          title={navItems.find(n => n.key === page)?.label || 'Ota-ona paneli'}
          subtitle={`Farzandlar: ${children.length}`}
          user={user}
          onMenuClick={() => setMobileMenu(true)}
        />
        <main className="flex-1 overflow-x-hidden overflow-y-auto">
          {page === 'home' && renderHome()}
          {page === 'children' && renderChildren()}
          {page === 'profile' && renderProfile()}
        </main>
        <MobileBottomNav items={navItems} activePage={page} setPage={setPage} />
      </div>

      {/* Tafsilotlar modali */}
      <Modal open={!!selectedChild} onClose={() => setSelectedChild(null)} title={selectedChild?.full_name || ''} width="max-w-2xl">
        {selectedChild && (
          <div className="space-y-3 max-h-[60vh] overflow-y-auto">
            {selectedChild.badges && selectedChild.badges.length > 0 && (
              <div className="pb-3 border-b border-white/5">
                <div className="text-[10px] text-white/40 uppercase mb-1.5 font-bold tracking-wider">Erishilgan nishonlar</div>
                <div className="flex flex-wrap gap-2">
                  {selectedChild.badges.map(b => (
                    <span
                      key={b.id}
                      className={`inline-flex items-center gap-1.5 text-[10px] md:text-xs font-bold text-white bg-gradient-to-r ${b.color || 'from-indigo-500 to-purple-500'} px-2.5 py-1.5 rounded-xl shadow-[0_4px_12px_rgba(99,102,241,0.2)]`}
                      title={b.description}
                    >
                      <span>{b.icon}</span>
                      <span>{b.title}</span>
                    </span>
                  ))}
                </div>
              </div>
            )}

            {/* Telegram settings */}
            <div className="pb-3 border-b border-white/5 space-y-3">
              <div className="text-[10px] text-white/40 uppercase font-bold tracking-wider">Haftalik Telegram Hisoboti</div>
              <div className="flex items-center justify-between bg-white/5 p-3 rounded-xl border border-white/5">
                <div className="min-w-0 flex-1 pr-3">
                  <div className="text-xs font-bold text-white">Telegram xabarnoma</div>
                  <p className="text-[10px] text-white/40 mt-0.5 leading-relaxed font-medium">Har yakshanba farzandingizning haftalik faoliyati bo'yicha hisobot ota-ona Telegramiga yuboriladi.</p>
                </div>
                <div className="flex items-center gap-2 flex-shrink-0">
                  <button
                    onClick={() => handleSendTestDigest(selectedChild.student_id)}
                    disabled={sendingDigestId === selectedChild.student_id}
                    className="btn-ghost text-[10px] px-2.5 py-1.5 rounded-lg border border-white/10 hover:bg-white/10 transition-colors"
                  >
                    {sendingDigestId === selectedChild.student_id ? "Yuborilmoqda..." : "Sinash (Test)"}
                  </button>
                  <button
                    onClick={() => handleToggleDigest(selectedChild.student_id, selectedChild.weekly_digest_enabled)}
                    disabled={digestTogglingId === selectedChild.student_id}
                    className={`text-[10px] px-3 py-1.5 rounded-lg font-bold transition-all ${
                      selectedChild.weekly_digest_enabled
                        ? 'bg-indigo-500 text-white'
                        : 'bg-white/5 text-white/40'
                    }`}
                  >
                    {selectedChild.weekly_digest_enabled ? "Yoqilgan" : "O'chirilgan"}
                  </button>
                </div>
              </div>
            </div>

            {/* AI Success Predictor */}
            <div className="pb-3 border-b border-white/5">
              <div className="text-[10px] text-white/40 uppercase mb-2 font-bold tracking-wider">AI Muvaffaqiyat Prognostikasi</div>
              {predictionsLoading ? (
                <div className="text-xs text-white/40 py-2">Prognostika yuklanmoqda...</div>
              ) : predictionsMap[selectedChild.student_id] ? (
                (() => {
                  const pData = predictionsMap[selectedChild.student_id];
                  return (
                    <div className="space-y-3">
                      <div className="grid grid-cols-3 gap-2 text-center">
                        <div className="glass rounded-xl p-2.5 border border-white/5">
                          <div className="text-[9px] text-white/40 truncate">Prezident Maktabi</div>
                          <div className="text-sm font-black text-indigo-400 mt-1">{pData.predictions?.presidential_school}%</div>
                        </div>
                        <div className="glass rounded-xl p-2.5 border border-white/5">
                          <div className="text-[9px] text-white/40 truncate">Al-Xorazmiy</div>
                          <div className="text-sm font-black text-purple-400 mt-1">{pData.predictions?.al_xorazmiy}%</div>
                        </div>
                        <div className="glass rounded-xl p-2.5 border border-white/5">
                          <div className="text-[9px] text-white/40 truncate">DTM (Kirish)</div>
                          <div className="text-sm font-black text-emerald-400 mt-1">{pData.predictions?.dtm}%</div>
                        </div>
                      </div>
                      <div className="glass rounded-xl p-3 text-xs text-white/70 leading-relaxed whitespace-pre-line border border-indigo-500/10">
                        <div className="font-bold text-white mb-1.5 flex items-center gap-1">
                          <span>💡</span> AI Ekspert Tavsiyalari:
                        </div>
                        {pData.ai_analysis}
                      </div>
                    </div>
                  );
                })()
              ) : (
                <div className="text-xs text-white/30 py-2">Imtihon topshirmagan o'quvchi uchun tahlil mavjud emas.</div>
              )}
            </div>

            <div className="text-[10px] text-white/40 uppercase mb-1.5 font-bold tracking-wider">Imtihonlar tarixi</div>
            {(selectedChild.attempts || []).length === 0 && (
              <div className="text-xs text-white/40 text-center py-4">Natijalar yo'q</div>
            )}
            {(selectedChild.attempts || []).map(a => (
              <div key={a.attempt_id} className="rounded-xl bg-white/5 p-3 border border-white/10">
                <div className="flex items-start justify-between gap-2 mb-2">
                  <div className="min-w-0 flex-1">
                    <div className="text-white font-medium text-sm truncate">{a.olympiad_title}</div>
                    <div className="text-xs text-white/40">{a.subject}</div>
                  </div>
                  <div className={`text-base font-bold flex-shrink-0 ${a.score >= 70 ? 'text-emerald-400' : a.score >= 50 ? 'text-amber-400' : 'text-rose-400'}`}>
                    {a.score}
                  </div>
                </div>
                <div className="flex items-center gap-3 text-[10px] text-white/40">
                  <span>To'g'ri: {a.correct_count}/{a.total_questions}</span>
                  {a.rank && <span>O'rin: #{a.rank}</span>}
                  <span className="ml-auto">{(a.submitted_at || '').slice(0, 10)}</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </Modal>
    </div>
  );
};

Object.assign(window, { ParentDashboard });


Object.assign(moduleScope, { ParentDashboard });
}
var ParentDashboard = moduleScope.ParentDashboard;

// app.jsx
{
// app.jsx — Main router & state (store-driven)

const { useState, useEffect } = React;

// Page <-> URL mapping. Brauzer manzil satrida sahifa o'zgarishini ko'rsatish
// va orqaga/oldinga tugmalari ishlashi uchun ishlatiladi.
//
// Eslatma: `results` sahifasi URL o'zgartirmaydi — u runtime state
// (testResult) bilan boshqariladi. `test` esa endi URL'ga bog'langan
// (/test/<id>) va F5'dan keyin sessiya localStorage'dan tiklanadi.
const PAGE_URLS = {
  landing: '/',
  login: '/login',
  register: '/register',
  student: '/dashboard',
  teacher: '/dashboard/teacher',
  manager: '/manager',
  owner: '/owner',
  admin: '/admin',
  questions: '/dashboard/questions',
  olympiads: '/dashboard/olympiads',
  results: '/dashboard/results',
  leaderboard: '/leaderboard',
  profile: '/profile',
  pending: '/pending',
  'pending-home': '/pending',
  analytics: '/analytics',
  parent: '/dashboard/parent',
};

// Faol test sahifasidagi olimpiada ID'sini saqlash kaliti. F5 (sahifa
// yangilash) yoki kraxdan keyin test sessiyasini shu ID orqali tiklaymiz.
const ACTIVE_TEST_KEY = 'olympy:activeTestOlympiad';

const readActiveTestId = () => {
  try { return localStorage.getItem(ACTIVE_TEST_KEY) || null; } catch { return null; }
};
const writeActiveTestId = (id) => {
  try {
    if (id == null) localStorage.removeItem(ACTIVE_TEST_KEY);
    else localStorage.setItem(ACTIVE_TEST_KEY, String(id));
  } catch {}
};

// URL'dan test olimpiada ID'sini ajratish: /test yoki /test/<id>.
const testIdFromPath = () => {
  try {
    const raw = window.location.pathname || '/';
    const m = raw.match(/^\/test(?:\/([^/]+))?\/?$/);
    if (!m) return undefined; // test sahifasi emas
    return m[1] || null; // ID bo'lmasa null (localStorage fallback ishlatiladi)
  } catch { return undefined; }
};

// URL → page (teskari mapping). Bir nechta page bitta URL ga ko'rsatsa,
// birinchi uchragani ishlaydi (Object.fromEntries oxirgisini saqlaydi,
// shuning uchun pending-home oldinroq turibdi va u pending'ni override
// qilmasligi kerak — `pending-home` faqat fallback sifatida ishlatiladi).
const URL_PAGES = (() => {
  const map = {};
  for (const [page, url] of Object.entries(PAGE_URLS)) {
    if (!(url in map)) map[url] = page;
  }
  return map;
})();

// Auth talab qiladigan sahifalar. Component tashqarisida `const` sifatida —
// har render'da qayta yaratilmasligi va useEffect bog'liqliklarini bekorga
// o'zgartirmasligi uchun.
const NEEDS_AUTH_PAGES = ['student','manager','admin','teacher','owner','test','results','leaderboard','profile','pending','pending-home','analytics','parent','questions','olympiads'];

const pageFromPath = () => {
  try {
    const raw = window.location.pathname || '/';
    const path = raw === '/' ? '/' : raw.replace(/\/+$/, '');
    // /test va /test/<id> — test sahifasi (dinamik segment URL_PAGES'da yo'q).
    if (/^\/test(\/.*)?$/.test(path)) return 'test';
    if (URL_PAGES[path]) return URL_PAGES[path];
    if (path === '/' || path === '') return 'landing';
  } catch {}
  return null;
};

const App = () => {
  const [page, setPage] = React.useState(() => pageFromPath() || 'landing');
  const [testResult, setTestResult] = React.useState(null);
  const [activeOlympiad, setActiveOlympiad] = React.useState(null);
  const [switcherOpen, setSwitcherOpen] = React.useState(false);
  const [apiUser, setApiUser] = React.useState(null);
  // restore tugamasidan oldin landing flicker'i ko'rinmasligi uchun bootstrap
  // bayrog'i: true bo'lsa, butun ekran loaderda turadi va shundan so'nggina
  // haqiqiy sahifa render bo'ladi.
  const [bootstrapping, setBootstrapping] = React.useState(true);

  const user = apiUser;

  // K5: Submit paytida 401 olib token muddati tugagan bo'lsa, foydalanuvchi
  // saqlangan olimpiada test sahifasiga avtomatik qaytishi kerak. Aks
  // holda javoblar localStorage'da qoladi-yu, lekin foydalanuvchi
  // dashboard'ga otib ketadi va qayta submit qilolmaydi.
  const tryResumePendingOlympiad = (u) => {
    if (!u?._api) return;
    try {
      const pendingId = localStorage.getItem('olympy:pendingOlympiadReturn');
      if (!pendingId || !globalThis.OlympyApi?.getOlympiads) return;
      const token = globalThis.OlympyApi?.getToken?.()
        ?? globalThis.OlympyApi?.loadAuth?.()?.token;
      globalThis.OlympyApi.getOlympiads(token).then((list) => {
        const target = (list || []).find(o => String(o.id) === String(pendingId));
        if (!target) {
          localStorage.removeItem('olympy:pendingOlympiadReturn');
          return;
        }
        const mapped = mapApiOlympiad(target);
        if (mapped?.status === 'active') {
          setActiveOlympiad(mapped);
          setPage('test');
        }
        localStorage.removeItem('olympy:pendingOlympiadReturn');
      }).catch(() => {
        // Tarmoq xatosi — pending'ni saqlab qoldiramiz, foydalanuvchi
        // qayta urinib ko'rishi mumkin.
      });
    } catch {}
  };

  // K17: F5 (sahifa yangilash) yoki to'g'ridan-to'g'ri /test/<id> link bilan
  // kirilganda test sessiyasini tiklash. URL'dagi ID yoki localStorage'dagi
  // faol test ID'si orqali olimpiadani topamiz. Faqat hali active bo'lgan
  // (vaqti tugamagan) olimpiada tiklanadi — javoblar localStorage'dagi
  // `olympy_answers_<id>` kalitidan OlympiadTest komponenti tomonidan
  // avtomatik o'qiladi. Promise qaytaradi: true => tiklash boshlandi.
  const tryRestoreActiveTest = (u, urlTestId) => {
    if (!u?._api || !globalThis.OlympyApi?.getOlympiads) return Promise.resolve(false);
    const targetId = (urlTestId != null && urlTestId !== '')
      ? urlTestId
      : readActiveTestId();
    if (!targetId) return Promise.resolve(false);
    const token = globalThis.OlympyApi?.getToken?.()
      ?? globalThis.OlympyApi?.loadAuth?.()?.token;
    return globalThis.OlympyApi.getOlympiads(token).then((list) => {
      const target = (list || []).find(o => String(o.id) === String(targetId));
      if (!target) { writeActiveTestId(null); return false; }
      const mapped = mapApiOlympiad(target);
      // Faqat active olimpiada tiklanadi. Yakunlangan/o'chirilgan bo'lsa
      // saqlangan ID'ni tozalaymiz va dashboard'da qoldiramiz.
      if (mapped?.status !== 'active') { writeActiveTestId(null); return false; }
      setActiveOlympiad(mapped);
      setPage('test');
      return true;
    }).catch(() => false);
  };

  // Persist backend JWT session only.
  useEffect(() => {
    let cancelled = false;
    const restore = async () => {
      const requestedPage = pageFromPath();
      const auth = globalThis.OlympyApi?.loadAuth?.();
      // localStorage'dagi user obyektiga ko'r-ko'rona ishonmaslik —
      // token eskirgan bo'lsa dashboard 401 olib bounce loop yaratadi.
      // Avval getMe bilan validate qilamiz.
      const urlTestId = testIdFromPath();
      if (auth?.user) {
        try {
          const freshUser = await globalThis.OlympyApi?.getMe?.(null);
          if (!freshUser || cancelled) throw new Error('Stale session');
          const mappedUser = globalThis.OlympyApi.mapBackendUser(freshUser);
          globalThis.OlympyApi.saveAuth({ user: mappedUser, cookieAuth: true });
          setApiUser(mappedUser);
          // F5'dan keyin test sahifasida bo'lsak — sessiyani tiklaymiz.
          if (requestedPage === 'test') {
            const restored = await tryRestoreActiveTest(mappedUser, urlTestId);
            if (cancelled) return;
            if (!restored) setPage(roleHomePage(mappedUser));
            setBootstrapping(false);
            return;
          }
          const publicPages = ['login', 'register', 'landing'];
          const dest1 = (!requestedPage || publicPages.includes(requestedPage))
            ? roleHomePage(mappedUser) : requestedPage;
          setPage(dest1);
          setBootstrapping(false);
          tryResumePendingOlympiad(mappedUser);
          return;
        } catch {
          // Token stale — tozalab cookie session sinab ko'ramiz
          try { globalThis.OlympyApi?.clearAuth?.(); } catch {}
        }
      }
      try {
        const freshUser = await globalThis.OlympyApi?.getMe?.(null);
        if (!freshUser || cancelled) throw new Error('No cookie session');
        const mappedUser = globalThis.OlympyApi.mapBackendUser(freshUser);
        globalThis.OlympyApi.saveAuth({ user: mappedUser, cookieAuth: true });
        setApiUser(mappedUser);
        if (requestedPage === 'test') {
          const restored = await tryRestoreActiveTest(mappedUser, urlTestId);
          if (cancelled) return;
          if (!restored) setPage(roleHomePage(mappedUser));
          return;
        }
        const publicPages2 = ['login', 'register', 'landing'];
        const dest2 = (!requestedPage || publicPages2.includes(requestedPage))
          ? roleHomePage(mappedUser) : requestedPage;
        setPage(dest2);
        tryResumePendingOlympiad(mappedUser);
        return;
      } catch {}
      // Autentifikatsiyasiz /test ochilsa — auth guard login'ga yo'naltiradi.
      if (!cancelled && requestedPage && requestedPage !== 'test') setPage(requestedPage);
    };
    try {
      restore().finally(() => { if (!cancelled) setBootstrapping(false); });
    } catch {
      if (!cancelled) setBootstrapping(false);
    }
    return () => { cancelled = true; };
  }, []);

  const handleLogin = (u) => {
    if (!u?._api) return;
    const requestedPage = pageFromPath();
    setApiUser(u);
    const publicPages = ['login', 'register', 'landing'];
    const dest = (!requestedPage || publicPages.includes(requestedPage))
      ? roleHomePage(u)
      : requestedPage;
    setPage(dest);
    tryResumePendingOlympiad(u);
  };

  const handleLogout = () => {
    setApiUser(null);
    setTestResult(null);
    setActiveOlympiad(null);
    setSwitcherOpen(false);
    // Logout'da faol test ID'sini ham tozalaymiz — boshqa foydalanuvchi
    // shu brauzerda kirsa eski testga tiklanib qolmasligi uchun.
    writeActiveTestId(null);
    try { globalThis.OlympyApi?.clearAuth?.(); } catch {}
    // Race-condition'ni oldini olish: agar foydalanuvchi allaqachon public
    // sahifada bo'lsa (login/register/landing), sahifani o'zgartirmaymiz.
    // Aks holda: foydalanuvchi "Kirish"ni bosib login'ga o'tadi, fonda eski
    // stale token bilan API 401 qaytaradi, 'olympy:logout' fires, va
    // login'dan landing'ga otib yuboriladi.
    setPage(currentPage =>
      ['landing', 'login', 'register'].includes(currentPage) ? currentPage : 'landing'
    );
  };

  // 401 javobi kelganda api.js auth state'ni tozalab 'olympy:logout' yuboradi.
  useEffect(() => {
    const onForcedLogout = () => handleLogout();
    window.addEventListener('olympy:logout', onForcedLogout);
    return () => window.removeEventListener('olympy:logout', onForcedLogout);
  }, []);

  const navigate = (dest, data) => {
    if (dest === 'test' && data) {
      setActiveOlympiad(data);
      // K17: test sessiyasini F5'dan keyin tiklash uchun olimpiada ID'sini
      // saqlaymiz va URL'ni /test/<id> ga o'tkazamiz.
      const testId = data.backendId ?? data.id ?? null;
      writeActiveTestId(testId);
      try {
        const url = testId != null ? `/test/${testId}` : '/test';
        if (window.location.pathname !== url) {
          window.history.pushState({ page: 'test' }, '', url);
        }
      } catch {}
      setPage('test');
      return;
    }
    if (dest === 'results' && data) {
      // Testdan natijaga o'tildi — faol test endi yo'q, saqlangan ID'ni tozalaymiz.
      writeActiveTestId(null);
      setTestResult(data);
      setPage('results');
      return;
    }
    // Boshqa har qanday sahifaga navigatsiya — faol test holatidan chiqadi.
    if (dest !== 'test') writeActiveTestId(null);
    setPage(dest);
  };

  // `page` o'zgarganda URL ni mos sinxronlash. PAGE_URLS da bor sahifalargina
  // pushState chaqiradi; `test` kabi runtime-only sahifalar URL o'zgartirmaydi.
  // Boshlang'ich render paytida URL allaqachon to'g'ri bo'lishi mumkin (deep
  // link) — bu holda pushState chaqirilmaydi.
  useEffect(() => {
    try {
      const url = PAGE_URLS[page];
      if (!url) return;
      if (window.location.pathname === url) return;
      window.history.pushState({ page }, '', url);
    } catch {}
  }, [page]);

  // Brauzer orqaga/oldinga tugmalari uchun popstate listener.
  useEffect(() => {
    const handler = (e) => {
      const pg = e.state?.page || pageFromPath();
      if (pg) setPage(pg);
    };
    window.addEventListener('popstate', handler);
    return () => window.removeEventListener('popstate', handler);
  }, []);

  const handleTestFinish = (result) => {
    // Test yakunlandi (submit yoki diskvalifikatsiya) — faol test ID'sini
    // tozalaymiz, aks holda F5'da tugagan testga qaytarib yuborardi.
    writeActiveTestId(null);
    setTestResult(result);
    setPage('results');
    const auth = globalThis.OlympyApi?.loadAuth?.();
    if (auth?.token && globalThis.OlympyApi?.getMe) {
      globalThis.OlympyApi.getMe(auth.token)
        .then(fresh => {
          const mapped = globalThis.OlympyApi.mapBackendUser(fresh);
          updateCurrentUser(mapped);
        })
        .catch(() => {});
    }
  };

  const switchRole = (role) => {
    if (!user) return;
    const nextUser = { ...user, activeRole: role };
    setApiUser(nextUser);
    try {
      const auth = globalThis.OlympyApi?.loadAuth?.();
      if (auth?.user) globalThis.OlympyApi.saveAuth({ token: auth.token, refresh: auth.refresh, user: nextUser });
    } catch {}
    setSwitcherOpen(false);
    setPage(ROLE_META[role]?.dest || 'student');
  };

  const updateCurrentUser = (nextUser) => {
    if (!nextUser?._api) return;
    setApiUser(nextUser);
    try {
      const auth = globalThis.OlympyApi?.loadAuth?.();
      globalThis.OlympyApi.saveAuth({ token: auth?.token, refresh: auth?.refresh, user: nextUser });
    } catch {}
  };

  // Auth guard
  useEffect(() => {
    if (NEEDS_AUTH_PAGES.includes(page) && !user) setPage('login');
  }, [page, user]);

  // ─── Role-gated dashboard renderer ────────────────────────────────────────
  const renderDashboard = (role) => {
    if (!user) return null;
    const status = getRoleStatus(user, role);
    const meta = ROLE_META[role];
    const data = user.roles?.[role];

    if (role === 'student' && status) {
      return (
        <StudentDashboard
          user={user}
          onNavigate={navigate}
          onLogout={handleLogout}
          onOpenSwitcher={() => setSwitcherOpen(true)}
          onUserUpdate={updateCurrentUser}
        />
      );
    }

    if (status === 'approved') {
      const props = {
        user, onNavigate: navigate, onLogout: handleLogout,
        onOpenSwitcher: () => setSwitcherOpen(true),
        onUserUpdate: updateCurrentUser,
      };
      if (role === 'student') return <StudentDashboard {...props} />;
      if (role === 'manager') return <ManagerDashboard {...props} />;
      if (role === 'teacher') return <TeacherDashboard {...props} />;
      if (role === 'owner')   return <OwnerDashboard {...props} />;
      if (role === 'admin')   return <AdminDashboard {...props} />;
    }

    if (status === 'pending') {
      const center = null;
      const messages = {
        manager: "Manager paneliga kirish uchun arizangiz tasdiqlanishi kerak. Ariza direktorga yuborildi.",
        teacher: "Savol yaratish uchun o'qituvchi arizangiz tasdiqlanishi kerak. Ariza direktorga yuborildi.",
        owner:   "Direktor paneliga kirish uchun markaz arizangiz Platform Admin tomonidan tasdiqlanishi kerak.",
        student: "Bu ekranga kirish uchun arizangiz tasdiqlanishi kerak.",
      };
      return (
        <PendingAccessCard
          title={`${meta?.label || ''} arizasi kutilmoqda`}
          status="pending"
          message={messages[role] || ''}
          extra={center && (
            <div className="glass rounded-2xl p-4 inline-flex items-center gap-3">
              <div className="w-10 h-10 gradient-bg rounded-xl flex items-center justify-center text-white font-bold">{center.name[0]}</div>
              <div className="text-left">
                <div className="text-sm font-semibold text-white">{center.name}</div>
                <div className="text-xs text-white/40">{center.city}</div>
              </div>
            </div>
          )}
          onBack={() => setPage(roleHomePage(user))}
        />
      );
    }

    if (status === 'rejected') {
      return (
        <PendingAccessCard
          title={`${meta?.label || ''} arizasi rad etildi`}
          status="rejected"
          message="Arizangiz qabul qilinmadi. Boshqa markaz tanlash yoki support bilan bog'lanish mumkin."
          onBack={() => setPage(roleHomePage(user))}
        />
      );
    }

    // No such role at all
    return (
      <PendingAccessCard
        title="Kirish ruxsat etilmagan"
        status="pending"
        message={`Sizda ${meta?.label || 'bu'} roli mavjud emas. Profil yoki Rolni almashtirish orqali boshqa rolga o'ting.`}
        onBack={() => setPage(roleHomePage(user))}
      />
    );
  };

  // ─── Page renderer ────────────────────────────────────────────────────────
  const renderPage = () => {
    switch (page) {
      case 'landing':       return <LandingPage onNavigate={navigate} user={user} />;
      case 'login':         return <LoginPage onNavigate={navigate} onLogin={handleLogin} />;
      case 'register':      return <RegisterPage onNavigate={navigate} onLogin={handleLogin} />;
      case 'pending-home':  return <PendingHome user={user} onLogout={handleLogout} onNavigate={navigate} />;
      case 'student':       return renderDashboard('student');
      case 'manager':       return renderDashboard('manager');
      case 'teacher':       return renderDashboard('teacher');
      case 'owner':         return renderDashboard('owner');
      case 'admin':         return renderDashboard('admin');
      case 'test': {
        const eventLabel = eventTypeLabel(activeOlympiad?.eventType || 'competition');
        if (activeOlympiad?.status !== 'active') {
          return (
            <PendingAccessCard
              title={`${eventLabel} faol emas`}
              status="pending"
              message={`${eventLabel} faollashtirilgandan keyin kirish mumkin.`}
              onBack={() => setPage(roleHomePage(user))}
            />
          );
        }
        // Public olympiads are open to every authenticated user. Center
        // competitions require approved student membership in the event center.
        const studentRole = user?.roles?.student;
        const isPublicOlympiad = (activeOlympiad?.eventType || 'competition') === 'olympiad';
        const canEnterCompetition = studentRole?.status === 'approved' &&
          studentRole.centerId &&
          String(studentRole.centerId) === String(activeOlympiad?.centerId);
        if (!isPublicOlympiad && !canEnterCompetition) {
          return (
            <PendingAccessCard
              title="Musobaqaga kirish cheklangan"
              status={studentRole?.status === 'rejected' ? 'rejected' : 'pending'}
              message="Musobaqaga qatnashish uchun shu o'quv markaz tasdig'i kerak."
              onBack={() => setPage(roleHomePage(user))}
            />
          );
        }
        return <OlympiadTestPage olympiad={activeOlympiad} user={user} onFinish={handleTestFinish} onNavigate={navigate} />;
      }
      case 'leaderboard': return (
        <div className="min-h-screen" style={{ background: '#050508' }}>
          <div className="glass border-b border-white/5 px-6 py-3 flex items-center gap-3">
            <button type="button" className="cursor-pointer border-0 bg-transparent p-0" onClick={() => navigate(roleHomePage(user))} aria-label="Dashboardga qaytish">
              <BrandLogo size="sm" />
            </button>
            <button onClick={() => navigate(roleHomePage(user))} className="ml-auto btn-ghost text-xs px-4 py-2 rounded-xl flex items-center gap-1.5">
              <Icon name="arrowLeft" size={13} /> Orqaga
            </button>
          </div>
          <LeaderboardPage onNavigate={navigate} user={user} />
        </div>
      );
      case 'profile': return (
        <div className="min-h-screen" style={{ background: '#050508' }}>
          <div className="glass border-b border-white/5 px-6 py-3 flex items-center gap-3">
            <button type="button" className="cursor-pointer border-0 bg-transparent p-0" onClick={() => navigate(roleHomePage(user))} aria-label="Dashboardga qaytish">
              <BrandLogo size="sm" />
            </button>
            <button onClick={() => navigate(roleHomePage(user))} className="ml-auto btn-ghost text-xs px-4 py-2 rounded-xl flex items-center gap-1.5">
              <Icon name="arrowLeft" size={13} /> Orqaga
            </button>
          </div>
          <ProfilePage user={user} onUserUpdate={updateCurrentUser} onNavigate={navigate} />
        </div>
      );
      // /dashboard/questions, /dashboard/olympiads, /dashboard/results deep
      // linklari ilgari renderPage switch'iga tushmasdi va LandingPage
      // ko'rinardi. Endi role home dashboard'iga yo'naltiramiz — u dashboard
      // ichidagi sub-tab orqali kerakli sahifani ochishi mumkin.
      case 'questions':
      case 'olympiads':
      case 'results':
        if (page === 'results' && testResult) {
          return (
            <div className="min-h-screen" style={{ background: '#050508' }}>
              <div className="glass border-b border-white/5 px-6 py-3 flex items-center gap-3">
                <button type="button" className="cursor-pointer border-0 bg-transparent p-0" onClick={() => navigate(roleHomePage(user))} aria-label="Dashboardga qaytish">
                  <BrandLogo size="sm" />
                </button>
                <button onClick={() => navigate(roleHomePage(user))} className="ml-auto btn-ghost text-xs px-4 py-2 rounded-xl flex items-center gap-1.5">
                  <Icon name="arrowLeft" size={13} /> Dashboardga qaytish
                </button>
              </div>
              <ResultsPage result={testResult} user={user} onNavigate={navigate} />
            </div>
          );
        }
        return renderDashboard(user?.activeRole || (user?.roles ? Object.keys(user.roles)[0] : 'student') || 'student');
      case 'pending':
        return <PendingHome user={user} onLogout={handleLogout} onNavigate={navigate} />;
      case 'analytics':
        return <AnalyticsPage user={apiUser || user} onNavigate={navigate} />;
      case 'parent':
        return <ParentDashboard user={apiUser || user} onNavigate={navigate} onLogout={handleLogout} />;
      default: return <LandingPage onNavigate={navigate} user={user} />;
    }
  };

  if (bootstrapping) {
    // Avval restore tugamaguncha "landing" sahifasi ko'rinib, keyin esa
    // foydalanuvchi dashboardiga sakrar va flicker hosil bo'lardi. Endi
    // bootstrap davomida loading skeleton ko'rsatamiz.
    return (
      <div className="dark min-h-screen flex items-center justify-center" style={{ background: '#050508' }}>
        <div className="flex flex-col items-center gap-4 text-white/70">
          <BrandLogo size="lg" />
          <div className="w-12 h-12 rounded-full border-2 border-white/20 border-t-white animate-spin" />
          <div className="text-sm font-semibold tracking-wide">Olympy yuklanmoqda...</div>
        </div>
      </div>
    );
  }

  // OB1: Onboarding sehrgar — faqat tizimga kirgan o'quvchi uchun va
  // onboarding tugatilmagan bo'lsa. Test/auth sahifalarida ko'rsatmaymiz
  // (test jarayonini buzmaslik uchun). Wizard butun ekranni egallaydi.
  const studentStatus = user?.roles?.student?.status;
  const showOnboarding = (
    !!user &&
    user.onboardingCompleted === false &&
    !!studentStatus &&
    !['test', 'login', 'register', 'landing'].includes(page)
  );

  return (
    <div key={page} className="dark">
      {renderPage()}
      {showOnboarding && (
        <OnboardingWizard
          user={user}
          onUserUpdate={updateCurrentUser}
          onComplete={() => {
            // user obyekti onUserUpdate orqali allaqachon yangilangan
            // (onboardingCompleted=true) — wizard avtomatik yopiladi.
            // Qo'shimcha kafolat: backend'dan yangi user'ni tortib olamiz.
            const auth = globalThis.OlympyApi?.loadAuth?.();
            if (globalThis.OlympyApi?.getMe) {
              globalThis.OlympyApi.getMe(auth?.token)
                .then(fresh => updateCurrentUser(globalThis.OlympyApi.mapBackendUser(fresh)))
                .catch(() => {});
            }
          }}
        />
      )}
      <RoleSwitcherModal
        open={switcherOpen}
        user={user}
        onClose={() => setSwitcherOpen(false)}
        onSwitch={switchRole}
        onLogout={handleLogout}
        onNavigate={navigate}
      />
    </div>
  );
};

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App />);


Object.assign(moduleScope, { PAGE_URLS, ACTIVE_TEST_KEY, readActiveTestId, writeActiveTestId, testIdFromPath, URL_PAGES, NEEDS_AUTH_PAGES, pageFromPath, App, root });
}
var PAGE_URLS = moduleScope.PAGE_URLS;
var ACTIVE_TEST_KEY = moduleScope.ACTIVE_TEST_KEY;
var readActiveTestId = moduleScope.readActiveTestId;
var writeActiveTestId = moduleScope.writeActiveTestId;
var testIdFromPath = moduleScope.testIdFromPath;
var URL_PAGES = moduleScope.URL_PAGES;
var NEEDS_AUTH_PAGES = moduleScope.NEEDS_AUTH_PAGES;
var pageFromPath = moduleScope.pageFromPath;
var App = moduleScope.App;
var root = moduleScope.root;

